const items = $input.all();
const results = [];

function clean(str) {
  if (!str) return "";
  return str
    .replace(/[^\x20-\x7E]/g, " ")  // Strip everything non-ASCII printable
    .replace(/\s+/g, " ")            // Collapse multiple spaces
    .trim();
}

function escapeForJson(str) {
  return str
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"')
    .replace(/\n/g, "\\n")
    .replace(/\r/g, "\\r")
    .replace(/\t/g, "\\t");
}

for (const item of items) {
  const jobTitle = clean(item.json.properties["Job Title"]?.title?.[0]?.plain_text);
  const company = clean(item.json.properties["Company"]?.rich_text?.[0]?.plain_text);
  const location = clean(item.json.properties["Location"]?.rich_text?.[0]?.plain_text);
  const jobDesc = clean(item.json.properties["Job Description"]?.rich_text?.[0]?.plain_text);
  const tailoredResume = clean(item.json.properties["Tailored Resume"]?.rich_text?.[0]?.plain_text);
  const notionPageId = item.json.id;

  const prompt = "Write a professional, concise cover letter for the following job. " +
    "Job Title: " + jobTitle + ". " +
    "Company: " + company + ". " +
    "Location: " + location + ". " +
    "Job Description: " + jobDesc + ". " +
    "Candidate Resume: " + tailoredResume + ". " +
    "Instructions: 3 paragraphs max. " +
    "Opening: express genuine interest in the role and company. " +
    "Middle: highlight 2-3 relevant skills from the resume that match the job. " +
    "Closing: confident call to action. " +
    "Tone: professional but human. " +
    "Output the cover letter text only.";

  const escapedPrompt = escapeForJson(prompt);

  const body = '{"model":"claude-haiku-4-5-20251001","max_tokens":1024,"messages":[{"role":"user","content":"' + escapedPrompt + '"}]}';

  results.push({
    json: {
      notionPageId: notionPageId,
      jobTitle: jobTitle,
      company: company,
      prompt: prompt
    }
  });
}

return results;

const httpItems = $input.all();
const promptItems = $('Code in JavaScript').all();
const results = [];

for (let i = 0; i < httpItems.length; i++) {
  const httpItem = httpItems[i];
  const promptItem = promptItems[i] || {};

  let coverLetter = "";

  try {
    const content = httpItem.json.content;
    if (content && content.length > 0) {
      coverLetter = content[0].text || "";
    }
  } catch(e) {
    coverLetter = "";
  }

  coverLetter = coverLetter.replace(/\[Your Name\]/g, "Nibras");

  if (coverLetter.length > 1900) {
    coverLetter = coverLetter.substring(0, 1900) + "...";
  }

  const notionPageId = promptItem.json?.notionPageId || "";

  // Only proceed if cover letter has real content
  if (coverLetter.length > 50 && notionPageId) {
    results.push({
      json: {
        notionPageId: notionPageId,
        coverLetter: coverLetter
      }
    });
  }
}

return results;
